import React from 'react';
import { connect } from 'react-redux';

function Userlist({ userlist }) {
  return (
    <>
      <h1>User List</h1>
      <ul>
          userlist.map(user => (
              <article>
                  <h3> </h3>
              </article>
          ))
      </ul>
    </>
  );
}
const mapStateToProps = (state) => ({
  userlist: state.userlist
});

export default connect(mapStateToProps, mapDispatchToProps)(Userlist);
